function q(
  block: 1 | 2 | 3 | 4,
  topic: string,
  type: "multiple-choice" | "true-false" | "open-answer",
  question: string,
  options: string[],
  correct_index: number,
  explanation: string
): SeedQuestion {
  return { block, topic, type, question, options, correct_index, explanation, topic_summary: SUMMARIES[topic] ?? "", further_reading: REFS[topic] ?? [], source: "hardcoded" }
}

export const SEED_QUESTIONS: SeedQuestion[] = [

  // ─────────────────────────────────────────────
  // BLOCK 1 - The Digital World
  // ─────────────────────────────────────────────

  // Living in a digital world
  q(1,"Living in a digital world","multiple-choice","Which of the following best describes the term 'digital'?",["Relating to fingers and hands","Representing data as discrete numerical values (0s and 1s)","A type of analogue signal","Wireless communication technology"],1,"**Digital** means representing information as discrete numerical values - specifically `0` and `1` in binary. This is different from analogue, which uses continuous values. All computers process digital data."),
  q(1,"Living in a digital world","multiple-choice","What does ICT stand for?",["Internet Connection Technology","Information and Communication Technology","Integrated Computing Tools","Input Control Technology"],1,"**ICT** stands for **Information and Communication Technology** - the broad field covering all technologies used to create, store, exchange, and manage information, including computers, smartphones, the internet, and software."),
  q(1,"Living in a digital world","true-false","The internet and the World Wide Web are the same thing.",["True","False"],1,"False. The **internet** is the global network of interconnected computers (the infrastructure). The **World Wide Web** (WWW) is a service that runs on top of the internet - a collection of web pages accessed via browsers using HTTP."),
  q(1,"Living in a digital world","multiple-choice","Which of the following is an example of digital communication?",["Writing a letter by hand","Speaking face to face","Sending an email","Using a telephone in the 1950s"],2,"**Email** is a form of digital communication - it transmits data as binary over the internet. Traditional telephone calls in the 1950s were analogue."),
  q(1,"Living in a digital world","multiple-choice","A 'bit' is:",["8 bytes","A type of memory chip","The smallest unit of digital data, representing 0 or 1","A unit of internet speed"],2,"A **bit** (binary digit) is the smallest unit of digital information. It has exactly two possible values: `0` or `1`. Eight bits make one **byte**."),
  q(1,"Living in a digital world","true-false","Smartphones are examples of digital devices.",["True","False"],0,"True. **Smartphones** process, store, and transmit data digitally. They contain processors that operate on binary data (0s and 1s), making them digital devices."),
  q(1,"Living in a digital world","multiple-choice","Which of these best describes 'data'?",["Instructions that tell a computer what to do","Raw facts and figures before they have been processed","The screen display of a computer","A type of network connection"],1,"**Data** refers to raw facts and figures - numbers, text, images, sounds - before they are processed or given meaning. Once processed and given context, data becomes **information**."),
  q(1,"Living in a digital world","open-answer","In your own words, explain the difference between data and information. Give one example of each.",[],- 1,"**Data** is raw, unprocessed facts and figures (e.g. the number `37`). **Information** is data that has been processed and given meaning in context (e.g. 'the temperature is 37 degrees Celsius'). Data becomes information when it is organised, labelled, and interpreted."),

  // The evolving computer
  q(1,"The evolving computer","multiple-choice","Which generation of computers was characterised by the use of vacuum tubes?",["First generation","Second generation","Third generation","Fourth generation"],0,"**First-generation** computers (1940s-1950s) used **vacuum tubes** as their main electronic component. They were enormous, expensive, and generated a huge amount of heat. **ENIAC** is a famous example."),
  q(1,"The evolving computer","multiple-choice","Which component replaced the vacuum tube in second-generation computers?",["Integrated circuit","Transistor","Microprocessor","Relay"],1,"**Second-generation** computers (late 1950s-1960s) replaced vacuum tubes with **transistors**, which were smaller, faster, cheaper, and far more energy-efficient."),
  q(1,"The evolving computer","true-false","The fourth generation of computers introduced the microprocessor - an entire CPU on a single chip.",["True","False"],0,"True. The **microprocessor** defines the fourth generation (1970s onwards). Intel's **4004** (1971) was one of the first commercially available microprocessors."),
  q(1,"The evolving computer","multiple-choice","Integrated circuits (ICs) were the defining technology of which generation of computers?",["First generation","Second generation","Third generation","Fifth generation"],2,"**Third-generation** computers (1960s-1970s) used **integrated circuits** - multiple transistors and components on a single silicon chip. This made computers much smaller, cheaper, and more reliable."),
  q(1,"The evolving computer","multiple-choice","What is Moore's Law?",["The law that governs internet speeds","The observation that the number of transistors on a chip roughly doubles every two years","A rule about software development costs","The maximum size of a database"],1,"**Moore's Law** is the observation by Gordon Moore (1965) that the number of transistors on a microchip doubles approximately every two years, leading to exponential improvements in computing power."),
  q(1,"The evolving computer","multiple-choice","What does CPU stand for?",["Central Processing Unit","Computer Power Usage","Core Processing Utility","Central Programming Unit"],0,"**CPU** stands for **Central Processing Unit** - the main processor of a computer that executes instructions, performs calculations, and controls the other hardware components."),
  q(1,"The evolving computer","true-false","Second-generation computers used punch cards as their primary input method.",["True","False"],0,"True. **Punch cards** were a major input method for both first and second-generation computers. Holes punched in specific positions represented data or instructions."),
  q(1,"The evolving computer","open-answer","Describe two key differences between first-generation and fourth-generation computers.",[],- 1,"First-generation computers (1940s) used **vacuum tubes** and were room-sized, extremely expensive, and used enormous amounts of power. Fourth-generation computers (1970s onwards) use **microprocessors** (millions of transistors on a single chip), are vastly smaller, cheaper, and far more energy-efficient. Other valid differences include reliability, speed, and cost."),

  // Digital media
  q(1,"Digital media","multiple-choice","What is 'sampling' in the context of digitising an audio signal?",["Compressing the audio file","Measuring the amplitude of the sound wave at regular time intervals","Converting binary back to sound","Removing background noise from a recording"],1,"**Sampling** means measuring the amplitude of an analogue audio signal at regular time intervals. The number of samples taken per second is the **sample rate** (e.g. `44,100 Hz` for CD audio)."),
  q(1,"Digital media","multiple-choice","In digital images, what does 'resolution' refer to?",["The number of colours used","The file size in kilobytes","The number of pixels in the image","The brightness of the screen"],2,"Image **resolution** is the number of **pixels** (picture elements) in the image, often expressed as width x height (e.g. `1920x1080`). More pixels = higher resolution = finer detail."),
  q(1,"Digital media","true-false","Increasing the bit depth of a digital image increases the number of colours that can be represented.",["True","False"],0,"True. **Bit depth** determines how many bits are used per pixel. `1-bit` = 2 colours; `8-bit` = 256 colours; `24-bit` = ~16.7 million colours. More bits = more colour range."),
  q(1,"Digital media","multiple-choice","What is the sample rate of standard CD audio?",["8,000 Hz","22,050 Hz","44,100 Hz","96,000 Hz"],2,"Standard CD audio uses a sample rate of **44,100 Hz** - meaning the amplitude is measured 44,100 times per second. This is sufficient to reproduce all frequencies audible to humans (up to about 20 kHz)."),
  q(1,"Digital media","multiple-choice","A pixel in a 24-bit colour image uses how many bits to store its colour?",["8 bits","16 bits","24 bits","32 bits"],2,"In a **24-bit** colour image, each pixel uses 24 bits (3 bytes): 8 bits for red, 8 for green, 8 for blue (RGB). This allows 2^24 = ~16.7 million possible colours."),
  q(1,"Digital media","multiple-choice","What does 'lossy compression' mean?",["The file cannot be compressed","Some data is permanently discarded to make the file smaller","The file is compressed without losing any data","The file is encrypted"],1,"**Lossy compression** (e.g. JPEG for images, MP3 for audio) permanently removes some data to achieve smaller file sizes. **Lossless compression** (e.g. PNG, FLAC) compresses without any data loss."),
  q(1,"Digital media","true-false","A higher sample rate always produces better quality audio.",["True","False"],0,"True (generally). A higher sample rate captures more detail from the original analogue signal. However, humans cannot hear above about 20 kHz, so very high sample rates (like 192 kHz) offer diminishing returns."),
  q(1,"Digital media","open-answer","Explain what 'bit depth' means in the context of digital images, and describe the effect of increasing it.",[],- 1,"**Bit depth** refers to the number of bits used to store the colour of each pixel. A higher bit depth allows more distinct colours to be represented. For example, 1-bit gives only 2 colours (black and white), while 8-bit gives 256 colours, and 24-bit gives over 16 million colours. Increasing bit depth produces images with smoother gradients and more accurate colour representation, but also larger file sizes."),

  // A world built of data
  q(1,"A world built of data","multiple-choice","In a relational database, what is a primary key?",["The first column in a table","A unique identifier for each record in a table","A password to access the database","A link to another table"],1,"A **primary key** is a field that uniquely identifies each record in a database table. No two rows can share the same primary key value, and it cannot be null."),
  q(1,"A world built of data","multiple-choice","Which of the following is a query language used to interact with relational databases?",["HTML","CSS","SQL","Python"],2,"**SQL** (Structured Query Language) is the standard language for interacting with relational databases - used to Create, Read, Update, and Delete data (CRUD operations)."),
  q(1,"A world built of data","multiple-choice","How many bits are in one byte?",["4","8","16","32"],1,"One byte equals **8 bits**. A byte can represent 2^8 = 256 different values (0 to 255)."),
  q(1,"A world built of data","multiple-choice","What is the decimal value of the binary number 1010?",["5","8","10","12"],2,"`1010` in binary = `(1x8) + (0x4) + (1x2) + (0x1)` = `8 + 2 = 10` in decimal."),
  q(1,"A world built of data","multiple-choice","What is the binary representation of the decimal number 13?",["1010","1100","1101","1111"],2,"13 in binary: 13 = 8+4+1 = `1101`. (13/2=6 r1; 6/2=3 r0; 3/2=1 r1; 1/2=0 r1. Read upward: **1101**.)"),
  q(1,"A world built of data","multiple-choice","How many bytes is 1 kilobyte (KB) in computing contexts?",["100 bytes","1000 bytes","1024 bytes","2000 bytes"],2,"In computing, `1 KB` traditionally equals **1024 bytes** (2^10). This is the binary definition used in TM111."),
  q(1,"A world built of data","multiple-choice","What does a foreign key do in a relational database?",["Uniquely identifies each record","Links a record in one table to a record in another table","Encrypts the database","Sets the default value of a field"],1,"A **foreign key** is a field in one table that refers to the **primary key** in another table, creating a link between them. This is how relational databases connect related data."),
  q(1,"A world built of data","multiple-choice","What is the decimal value of binary 11111111?",["127","255","256","512"],1,"`11111111` = 128+64+32+16+8+4+2+1 = **255**. This is the maximum value storable in one byte."),
  q(1,"A world built of data","multiple-choice","What is the binary value of decimal 7?",["0110","0111","1000","1001"],1,"7 in binary = **0111** (4+2+1 = 7)."),
  q(1,"A world built of data","true-false","All data stored on a computer is ultimately represented as binary (0s and 1s).",["True","False"],0,"True. All data - text, images, audio, video, programs - is ultimately represented as **binary** (sequences of 0s and 1s). Different encodings define how binary patterns map to meaningful data."),
  q(1,"A world built of data","open-answer","In your own words, explain what a database primary key is and why it is important.",[],- 1,"A **primary key** is a unique identifier for each record (row) in a database table. It is important because it guarantees that every record can be identified individually - no two records can share the same primary key value. Primary keys also enable records in different tables to be linked via foreign keys, which is fundamental to how relational databases work."),

  // Weaving the web
  q(1,"Weaving the web","multiple-choice","What does HTML stand for?",["Hyper Transfer Markup Language","HyperText Markup Language","HyperText Management Language","High Text Markup Language"],1,"**HTML** stands for **HyperText Markup Language**. It is the standard language for structuring content on web pages, using elements called tags (e.g. `<h1>`, `<p>`, `<a>`)."),
  q(1,"Weaving the web","true-false","CSS is used to define the structure and content of a web page, while HTML controls the appearance.",["True","False"],1,"False. **HTML** defines structure and content; **CSS** (Cascading Style Sheets) controls the visual presentation (colours, fonts, layout, etc.)."),
  q(1,"Weaving the web","multiple-choice","What does URL stand for?",["Universal Resource Locator","Uniform Resource Locator","Unique Retrieval Link","Universal Reference Label"],1,"**URL** stands for **Uniform Resource Locator** - the address of a resource on the web (e.g. `https://www.open.ac.uk/`)."),
  q(1,"Weaving the web","multiple-choice","Which protocol is used to securely transfer web pages over the internet?",["FTP","HTTP","HTTPS","SMTP"],2,"**HTTPS** (HyperText Transfer Protocol Secure) is the secure version of HTTP. It encrypts data using **TLS**, protecting it from interception."),
  q(1,"Weaving the web","multiple-choice","What is the role of a web browser?",["To store web pages on a server","To request and display web pages by interpreting HTML, CSS, and JavaScript","To send emails","To create databases"],1,"A **web browser** (Chrome, Firefox, Safari) requests web pages from servers using HTTP/HTTPS, then interprets the HTML, CSS, and JavaScript to display the page visually."),
  q(1,"Weaving the web","multiple-choice","What does a web server do?",["Browses the internet for information","Stores and delivers web pages to browsers when requested","Manages email accounts","Provides WiFi signals"],1,"A **web server** stores web pages and delivers them to browsers when requested via HTTP. When you type a URL, your browser sends a request to the appropriate web server, which responds with the page."),
  q(1,"Weaving the web","true-false","JavaScript is used to add interactivity to web pages.",["True","False"],0,"True. **JavaScript** is a programming language that runs in the browser and adds dynamic behaviour - such as responding to button clicks, form validation, and updating content without reloading the page."),
  q(1,"Weaving the web","open-answer","Explain the difference between HTML and CSS, and describe the role each plays in a web page.",[],- 1,"**HTML** (HyperText Markup Language) defines the structure and content of a web page - it specifies headings, paragraphs, links, images, and other elements using tags. **CSS** (Cascading Style Sheets) controls how those elements look - their colours, fonts, sizes, spacing, and layout. HTML is about what is on the page; CSS is about how it appears. A page can work with HTML alone but will look plain and unstyled without CSS."),

  // Crossing boundaries - HCI and design
  q(1,"Crossing boundaries - HCI and design","multiple-choice","Which of the following is a key usability principle defined by Jakob Nielsen?",["Optimisation","Error prevention","Data encryption","Load balancing"],1,"Jakob Nielsen's 10 usability heuristics include **Error prevention** - designing systems that prevent problems from occurring in the first place is better than relying on good error messages alone."),
  q(1,"Crossing boundaries - HCI and design","multiple-choice","Accessibility in computing refers to designing systems that can be used by:",["Only expert programmers","People with disabilities as well as all other users","Users who pay for premium access","Administrators only"],1,"**Accessibility** means designing technology so that people with disabilities (visual, hearing, motor, or cognitive impairments) can use it effectively - alongside all other users."),
  q(1,"Crossing boundaries - HCI and design","multiple-choice","What does HCI stand for?",["Hardware Control Interface","Human Computer Interaction","High Capacity Integration","Hypertext Content Index"],1,"**HCI** stands for **Human Computer Interaction** - the study of how people interact with computers and how to design interfaces that are effective, efficient, and satisfying to use."),
  q(1,"Crossing boundaries - HCI and design","multiple-choice","Which of the following is an example of a haptic (tactile) interface?",["A computer monitor","A vibrating phone notification","A keyboard shortcut","A drop-down menu"],1,"**Haptic** interfaces communicate through touch and physical sensation. A **vibrating phone notification** is a haptic feedback example. Other examples include game controller rumble and force-feedback steering wheels."),
  q(1,"Crossing boundaries - HCI and design","true-false","A system that is easy for expert users to operate is always considered to have good usability.",["True","False"],1,"False. Good **usability** means the system works well for its **intended users**, which may include beginners, older users, or people with disabilities. A system optimised only for experts may be inaccessible to others."),
  q(1,"Crossing boundaries - HCI and design","multiple-choice","What does the term 'affordance' mean in interface design?",["The cost of software","The perceived property of an object that suggests how it should be used","The speed of a processor","The memory capacity of a device"],1,"An **affordance** is a design property that suggests how an object should be used. A button that looks raised affords pressing. Good interfaces use clear affordances so users instinctively know how to interact."),
  q(1,"Crossing boundaries - HCI and design","multiple-choice","Which of Nielsen's heuristics means the system should always keep users informed about what is going on?",["User control and freedom","Visibility of system status","Error prevention","Consistency and standards"],1,"**Visibility of system status** means the system should always keep users informed about what is going on, through appropriate feedback within a reasonable time. For example, a loading bar while a file uploads."),
  q(1,"Crossing boundaries - HCI and design","open-answer","Describe what 'usability' means in interface design and give two examples of good usability practices.",[],- 1,"**Usability** refers to how easy and effective a system is for its intended users. A usable interface allows users to achieve their goals quickly, with minimal errors, and with satisfaction. Examples of good usability practices include: clear and consistent navigation so users always know where they are and how to get back; informative error messages that explain what went wrong and how to fix it; undo functionality so users can recover from mistakes; and using familiar icons or conventions that users already recognise."),

  // ─────────────────────────────────────────────
  // BLOCK 2 - Creating Solutions
  // ─────────────────────────────────────────────

  // Programming with Scratch - sequences and sprites
  q(2,"Programming with Scratch - sequences and sprites","multiple-choice","What is an algorithm?",["A type of programming language","A step-by-step set of instructions to solve a problem","A computer's operating system","A method of storing data"],1,"An **algorithm** is a finite, ordered sequence of well-defined instructions that describes how to solve a problem. Algorithms are independent of any specific programming language."),
  q(2,"Programming with Scratch - sequences and sprites","true-false","In programming, 'sequencing' means that instructions are executed one after another in the order they are written.",["True","False"],0,"True. **Sequencing** is one of the three fundamental constructs in programming (along with **selection** and **iteration**). Instructions run top-to-bottom in sequence unless redirected by another construct."),
  q(2,"Programming with Scratch - sequences and sprites","multiple-choice","In Scratch, what is a 'sprite'?",["A type of background image","An object on the stage that can be controlled with scripts","A variable that stores a number","A block that plays a sound"],1,"A **sprite** is an object on the Scratch stage that can be controlled using scripts. Sprites can move, change costume, play sounds, and interact with other sprites."),
  q(2,"Programming with Scratch - sequences and sprites","multiple-choice","Which Scratch block would you use to start a script when the user clicks the green flag?",["when this sprite clicked","when green flag clicked","forever","go to x:0 y:0"],1,"The **'when green flag clicked'** block is an event block that starts a script when the user presses the green flag button. It is the most common way to begin a Scratch program."),
  q(2,"Programming with Scratch - sequences and sprites","multiple-choice","Which of the following best describes 'decomposition' in computing?",["Deleting parts of a program","Breaking a complex problem into smaller, more manageable parts","Combining two programs into one","Translating code into another language"],1,"**Decomposition** is the process of breaking a complex problem into smaller, more manageable sub-problems. Each sub-problem can then be solved individually."),
  q(2,"Programming with Scratch - sequences and sprites","multiple-choice","In Scratch, which category of blocks contains 'move 10 steps'?",["Control","Looks","Motion","Events"],2,"The **Motion** blocks category contains blocks for moving and positioning sprites, including 'move 10 steps', 'turn 15 degrees', 'go to x: y:', and 'point in direction'."),
  q(2,"Programming with Scratch - sequences and sprites","true-false","A flowchart is a useful tool for planning an algorithm before writing code.",["True","False"],0,"True. **Flowcharts** use standard shapes (ovals for start/end, rectangles for processes, diamonds for decisions) to visually represent the steps and flow of an algorithm. They help plan logic before coding."),
  q(2,"Programming with Scratch - sequences and sprites","open-answer","In your own words, explain what an algorithm is. Describe a simple real-world algorithm you follow in everyday life.",[],- 1,"An **algorithm** is a precise, step-by-step set of instructions for completing a task or solving a problem. Every step must be clear and unambiguous. A real-world example is a recipe: it lists ingredients (inputs) and numbered steps to follow in sequence, producing a meal (output). Other examples include the steps to tie shoelaces, make a cup of tea, or find a word in a dictionary."),

  // Numbers, strings and lists
  q(2,"Numbers, strings and lists","multiple-choice","In Scratch, what is a variable?",["A block that plays a sound","A named storage location that can hold a value","A type of loop","A conditional statement"],1,"A **variable** is a named container in memory that stores a value (number, text, etc.) which can change as the program runs."),
  q(2,"Numbers, strings and lists","multiple-choice","Which of the following is an example of string concatenation?",["10 + 5 = 15","Joining 'Hello' and ' World' to make 'Hello World'","Setting a variable to 0","Multiplying two numbers"],1,"**String concatenation** means joining two or more strings end-to-end. `'Hello' + ' World'` produces `'Hello World'`. In Scratch, the `join` block performs concatenation."),
  q(2,"Numbers, strings and lists","multiple-choice","What is the index of the first item in a Scratch list?",["0","1","2","It has no index"],1,"In Scratch, list items are **indexed starting from 1**. So the first item is at index 1, the second at index 2. Many other programming languages (like Python) use 0-based indexing."),
  q(2,"Numbers, strings and lists","true-false","In Scratch, the result of joining the strings '24' and '7' is the number 31.",["True","False"],1,"False. **Joining** strings `'24'` and `'7'` produces the string `'247'`, not the number 31. Concatenation joins text end-to-end; it does not add numbers."),
  q(2,"Numbers, strings and lists","multiple-choice","What does it mean to 'initialise' a variable?",["Delete the variable","Give the variable its first (starting) value","Change the variable name","Make the variable invisible"],1,"**Initialising** a variable means setting it to a starting value before the main program runs. For example, setting a `score` variable to `0` at the start. Without initialisation, a variable may contain an unexpected value."),
  q(2,"Numbers, strings and lists","multiple-choice","Which Scratch block would you use to add 1 to a variable called 'score'?",["set score to 1","change score by 1","show variable score","delete score"],1,"The **'change [score] by 1'** block increments the variable by the given amount. `set score to 1` replaces the current value with 1. 'change by' adds to the existing value."),
  q(2,"Numbers, strings and lists","multiple-choice","What is a 'list' in programming?",["A type of loop","A collection of multiple values stored under a single variable name","A set of instructions","A type of conditional statement"],1,"A **list** (or array) stores multiple values under one name. Each item is accessed by its position (index). In Scratch, lists are shown as a scrollable box on the stage."),
  q(2,"Numbers, strings and lists","open-answer","Explain the difference between a variable and a list in Scratch. Give an example of when you would use each.",[],- 1,"A **variable** stores a single value at a time - for example, a `score` variable holds one number. A **list** stores multiple values under one name - for example, a `high_scores` list could hold the top 10 scores. Use a variable for a single piece of data that changes (like the current score), and a list when you need to store and manage a collection of related values (like all student names in a class)."),

  // Selection and Booleans
  q(2,"Selection and Booleans","multiple-choice","In Scratch, what does an 'if-then-else' block do?",["Repeats a set of blocks a fixed number of times","Executes one set of blocks if a condition is true, and a different set if it is false","Waits until a key is pressed","Defines a new variable"],1,"An **if-then-else** block checks a condition. If the condition is `TRUE` the 'then' branch runs; if `FALSE` the 'else' branch runs. This allows programs to make decisions."),
  q(2,"Selection and Booleans","true-false","A program can only have one 'if' statement in total.",["True","False"],1,"False. A program can contain many `if` / `if-else` statements. They can also be **nested** (an if inside another if) to handle complex decision-making."),
  q(2,"Selection and Booleans","multiple-choice","What is a Boolean value?",["A number between 0 and 100","A value that is either true or false","A type of string","A block category in Scratch"],1,"A **Boolean** (named after mathematician George Boole) is a data type with only two possible values: `true` or `false`. Boolean values are the result of conditions and comparisons."),
  q(2,"Selection and Booleans","multiple-choice","In Scratch, what does the 'and' operator do?",["Combines two strings","Returns true only if both conditions are true","Returns true if at least one condition is true","Inverts a Boolean value"],1,"The **'and'** operator returns `true` only if **both** conditions on either side are true. For example, `(score > 5) and (lives > 0)` is true only if both conditions are met."),
  q(2,"Selection and Booleans","multiple-choice","What is the result of the expression (10 > 5) and (3 < 2)?",["true","false","10","error"],1,"`(10 > 5)` is `true`. `(3 < 2)` is `false`. `true AND false = false`. The **'and'** operator only returns true when BOTH sides are true."),
  q(2,"Selection and Booleans","multiple-choice","What is the result of the expression NOT (5 > 10)?",["true","false","5","error"],0,"`(5 > 10)` is `false`. `NOT false = true`. The **'not'** operator inverts a Boolean value."),
  q(2,"Selection and Booleans","true-false","In an if-then block (without an else), if the condition is false, the program simply moves on to the next instruction.",["True","False"],0,"True. An **if-then** block (without else) simply skips the enclosed blocks if the condition is `false`, and execution continues with whatever comes after the if-then block."),
  q(2,"Selection and Booleans","open-answer","Explain what a Boolean value is and give two examples of conditions in a program that would produce a Boolean result.",[],- 1,"A **Boolean** is a value that can only be `true` or `false`. Conditions in programs evaluate to Boolean results. Examples: `(score > 50)` - this is true if the score variable holds a value above 50, and false otherwise. `(playerName = 'Alice')` - this is true if the name is Alice and false otherwise. Boolean results are used in if statements and loops to control what the program does next."),

  // Loops
  q(2,"Loops","multiple-choice","In Scratch, which loop block would you use to repeat a set of actions exactly 5 times?",["forever","repeat 5","if-then","wait 5 seconds"],1,"The `repeat (n)` block runs the enclosed blocks exactly `n` times - this is a **count-controlled loop**. `forever` loops indefinitely; `if-then` is a selection construct."),
  q(2,"Loops","multiple-choice","What is an infinite loop?",["A loop that runs a set number of times","A loop that never ends because its exit condition is never met","A loop that counts down from 10","A loop inside another loop"],1,"An **infinite loop** runs forever because the condition to stop it is never satisfied. In Scratch, the `forever` block is an intentional infinite loop. Accidental infinite loops are a common bug."),
  q(2,"Loops","multiple-choice","What is the difference between a count-controlled loop and a condition-controlled loop?",["They are the same thing","A count-controlled loop repeats a set number of times; a condition-controlled loop repeats until a condition is met","A count-controlled loop never stops; a condition-controlled loop runs once","Count-controlled loops are only in Scratch"],1,"A **count-controlled loop** (e.g. `repeat 10`) runs a fixed number of times. A **condition-controlled loop** (e.g. `repeat until`) keeps running until the specified condition becomes true."),
  q(2,"Loops","multiple-choice","In Scratch, the 'repeat until' block is an example of which type of loop?",["Count-controlled loop","Condition-controlled loop","Infinite loop","Nested loop"],1,"**'repeat until'** is a **condition-controlled loop** - it keeps repeating until the specified condition becomes `true`."),
  q(2,"Loops","true-false","Using a loop to repeat an action 100 times takes less code than writing the action out 100 times.",["True","False"],0,"True. A **loop** allows you to write the action once and specify how many times it repeats. Writing it out 100 times would produce 100x more code - making programs much harder to read and maintain."),
  q(2,"Loops","multiple-choice","What is a nested loop?",["A loop with no exit condition","A loop that is placed inside another loop","A loop that counts backwards","A loop that runs only once"],1,"A **nested loop** is a loop placed inside another loop. For each iteration of the outer loop, the inner loop runs its full set of iterations. Nested loops are useful for grids, patterns, or combinations."),
  q(2,"Loops","true-false","The 'forever' block in Scratch stops automatically when the green flag is clicked again.",["True","False"],1,"False. The `forever` block runs indefinitely and **does not stop automatically**. The user must click the red stop button, or the script must be stopped by a `stop all` block within the program."),
  q(2,"Loops","open-answer","Explain what a loop is in programming and describe the difference between a count-controlled loop and a condition-controlled loop.",[],- 1,"A **loop** is a programming construct that causes a block of code to be repeated multiple times. A **count-controlled loop** repeats a fixed number of times - for example, 'repeat 10' always executes exactly 10 times. A **condition-controlled loop** repeats until a condition becomes true - for example, 'repeat until the score reaches 100'. Count-controlled loops are used when you know in advance how many repetitions are needed; condition-controlled loops are used when the number of repetitions depends on what happens during the program."),

  // Nested structures and modularity
  q(2,"Nested structures and modularity","multiple-choice","What is the main benefit of breaking a program into smaller modules or functions?",["It makes the program run faster on older hardware","It makes code reusable, easier to read, and easier to test","It removes the need for variables","It automatically fixes bugs"],1,"**Modular programming** divides a program into self-contained units. Key benefits: code **reuse** (write once, call many times), easier debugging, improved readability, and easier collaboration."),
  q(2,"Nested structures and modularity","multiple-choice","In Scratch, what is the equivalent of a custom function or procedure?",["A variable","A sprite","A custom block ('My Blocks')","A backdrop"],2,"In Scratch, **My Blocks** act like **functions** or **procedures** - defined once, then called wherever needed. This avoids repeating the same blocks of code."),
  q(2,"Nested structures and modularity","multiple-choice","What does 'abstraction' mean in computing?",["Writing faster code","Hiding complex details and showing only the essential features","Making programs larger","Translating programs to different languages"],1,"**Abstraction** means hiding unnecessary complexity and showing only what is relevant. Custom blocks in Scratch are an example - you call a block without needing to know how it is implemented inside."),
  q(2,"Nested structures and modularity","true-false","A well-decomposed program is easier to test than one large block of code.",["True","False"],0,"True. When a program is **decomposed** into smaller modules, each module can be tested independently. This makes finding and fixing bugs much easier than testing a single large block of code."),
  q(2,"Nested structures and modularity","multiple-choice","If an if statement is placed inside a loop, this is an example of:",["A custom block","A nested structure","A Boolean expression","An infinite loop"],1,"Placing one control structure (like an `if`) inside another (like a `loop`) creates a **nested structure**. Nesting allows complex logic - for example, checking a condition on every iteration of a loop."),
  q(2,"Nested structures and modularity","multiple-choice","What does 'DRY' stand for in programming?",["Do Repeat Yourself","Don't Repeat Yourself","Dynamic Runtime Yielding","Direct Register Yoke"],1,"**DRY** stands for **Don't Repeat Yourself** - the principle that every piece of knowledge or logic should be represented only once in a program. Functions and custom blocks help achieve DRY code."),
  q(2,"Nested structures and modularity","open-answer","Explain what 'modular programming' means and give two benefits of organising code into modules or functions.",[],- 1,"**Modular programming** means dividing a large program into smaller, self-contained sections called modules or functions, each responsible for one specific task. Benefits include: **reusability** - a module can be called multiple times without rewriting the code; **easier debugging** - when something goes wrong, you can test each module separately to find the problem; **readability** - a well-named function makes the main program easier to understand at a glance; and **teamwork** - different people can work on different modules simultaneously."),

  // Algorithms and sorting
  q(2,"Algorithms and sorting","multiple-choice","What is a 'bug' in a computer program?",["A virus that infects the program","An error or flaw that causes the program to produce an unexpected result","A feature added later in development","A comment in the source code"],1,"A **bug** is an error in a program that causes it to behave incorrectly. Types include **syntax errors** (bad grammar), **logic errors** (correct syntax but wrong logic), and **runtime errors** (crashes during execution)."),
  q(2,"Algorithms and sorting","multiple-choice","In bubble sort, what happens in each pass through the list?",["Items are split into two halves","Adjacent items are compared and swapped if they are in the wrong order","The smallest item is moved to the front","Items are randomly rearranged"],1,"In **bubble sort**, each pass compares adjacent pairs of items and swaps them if they are out of order. After each pass, the largest unsorted item 'bubbles' to its correct position at the end."),
  q(2,"Algorithms and sorting","true-false","Testing a program with only inputs you expect it to handle correctly is sufficient to confirm it works.",["True","False"],1,"False. Good testing includes **normal data** (expected inputs), **boundary/edge cases** (extreme values), and **erroneous data** (invalid inputs). Testing only the 'happy path' leaves many bugs undiscovered."),
  q(2,"Algorithms and sorting","multiple-choice","Which sorting algorithm works by repeatedly splitting a list in half, sorting each half, and merging them back?",["Bubble sort","Selection sort","Merge sort","Insertion sort"],2,"**Merge sort** is a divide-and-conquer algorithm: it splits the list in half recursively until each piece has one element, then merges pairs back in sorted order. It is much more efficient than bubble sort for large lists."),
  q(2,"Algorithms and sorting","multiple-choice","What does 'efficient' mean when describing an algorithm?",["The algorithm produces a colourful output","The algorithm solves the problem using as few steps or as little time and memory as possible","The algorithm is written in Python","The algorithm has been tested"],1,"An **efficient** algorithm accomplishes its task using minimal resources - fewer steps, less time, or less memory. For large datasets, efficiency is critical."),
  q(2,"Algorithms and sorting","multiple-choice","What are the three types of test data that should be used when testing a program?",["Fast, slow, and normal","Normal, boundary, and erroneous","Integer, string, and Boolean","Syntax, logic, and runtime"],1,"Good testing uses: **normal data** (typical inputs), **boundary data** (extreme values at the edge of what is acceptable), and **erroneous data** (invalid inputs the program should handle gracefully)."),
  q(2,"Algorithms and sorting","true-false","Merge sort is generally faster than bubble sort for large lists.",["True","False"],0,"True. Bubble sort has worst-case complexity of O(n^2) - for n items it may make n^2/2 comparisons. Merge sort has O(n log n) complexity, which is dramatically faster for large lists."),
  q(2,"Algorithms and sorting","open-answer","Describe how bubble sort works. How many comparisons are made in the worst case for a list of 4 items?",[],- 1,"**Bubble sort** works by repeatedly passing through the list and comparing each pair of adjacent items. If a pair is in the wrong order, they are swapped. This continues until no swaps are needed in a full pass. For a list of 4 items in the worst case (completely reversed): pass 1 makes 3 comparisons, pass 2 makes 2, pass 3 makes 1 - giving 6 comparisons in total. Generally, the worst case for n items is n(n-1)/2 comparisons."),

  // ─────────────────────────────────────────────
  // BLOCK 3 - Connecting People, Places and Things
  // ─────────────────────────────────────────────

  // Network technologies
  q(3,"Network technologies","multiple-choice","What is an IP address?",["A unique physical address burned into a network card","A numerical label assigned to each device connected to a network","The name of a website","A type of network cable"],1,"An **IP address** (Internet Protocol address) is a numerical label (e.g. `192.168.1.1`) assigned to each device on a network - used to identify and locate it for routing."),
  q(3,"Network technologies","multiple-choice","What is a 'packet' in networking?",["A physical box used to ship network equipment","A small unit of data transmitted over a network","A type of wireless signal","A security certificate"],1,"Data sent over the internet is broken into small chunks called **packets**. Each packet contains a portion of the data plus a **header** (source IP, destination IP, sequence number)."),
  q(3,"Network technologies","multiple-choice","What is the difference between a LAN and a WAN?",["LANs are wireless; WANs are wired","A LAN covers a small area (e.g. a building); a WAN covers large distances (e.g. the internet)","LANs are faster than WANs","WANs are private; LANs are public"],1,"A **LAN** (Local Area Network) connects devices in a small area. A **WAN** (Wide Area Network) connects devices across large distances. The internet is the world's largest WAN."),
  q(3,"Network technologies","multiple-choice","What does a router do?",["Connects devices within the same local network","Forwards packets between different networks towards their destination","Converts analogue signals to digital","Stores web pages"],1,"A **router** receives packets and forwards them towards their destination, making decisions about the best route to take. Routers connect different networks - for example, your home network to the internet."),
  q(3,"Network technologies","true-false","All packets in a single data transmission always travel along exactly the same route through the internet.",["True","False"],1,"False. **Packet switching** allows different packets from the same message to take different routes. They are reassembled in the correct order at the destination using sequence numbers."),
  q(3,"Network technologies","multiple-choice","What is a MAC address?",["A unique identifier assigned by an internet service provider","A permanent physical address built into a network interface card","The address of a web page","A type of wireless encryption"],1,"A **MAC address** (Media Access Control address) is a unique hardware identifier permanently assigned to a network interface card during manufacture. Unlike an IP address, a MAC address is a physical address."),
  q(3,"Network technologies","true-false","A switch connects devices within the same network and sends data only to the intended recipient device.",["True","False"],0,"True. A **switch** connects multiple devices within the same LAN. Unlike a hub (which sends data to all devices), a switch uses MAC addresses to send data only to the specific intended device."),
  q(3,"Network technologies","open-answer","Explain what a packet is in networking and describe why data is sent in packets rather than as one continuous stream.",[],- 1,"A **packet** is a small unit of data that includes part of the message being sent, plus a header containing information like the source IP address, destination IP address, and sequence number. Data is sent in packets for several reasons: if part of the data is lost or corrupted, only that packet needs to be resent rather than the whole message; packets from different users can share the same network links simultaneously; and different packets can take different routes to avoid congestion, making networks more efficient and resilient."),

  // The internet
  q(3,"The internet","multiple-choice","What does HTTP stand for?",["HyperText Transfer Protocol","High Traffic Transmission Protocol","Hyper Transfer Text Program","Host Terminal Transfer Protocol"],0,"**HTTP** (HyperText Transfer Protocol) is the foundation of data communication on the World Wide Web. **HTTPS** is its secure version, adding encryption via TLS/SSL."),
  q(3,"The internet","multiple-choice","In the TCP/IP model, which layer is responsible for routing packets between networks?",["Application layer","Transport layer","Internet layer","Link layer"],2,"The **Internet layer** in TCP/IP handles **IP addressing** and **routing** - determining the best path for packets from source to destination across multiple networks."),
  q(3,"The internet","true-false","TCP (Transmission Control Protocol) guarantees that data packets arrive in order and without errors.",["True","False"],0,"True. **TCP** is a connection-oriented protocol providing **reliable**, **ordered**, and **error-checked** delivery. It uses acknowledgements (ACKs) and retransmission to ensure all packets arrive correctly."),
  q(3,"The internet","multiple-choice","What does DNS stand for and what does it do?",["Data Network System - stores network passwords","Domain Name System - translates domain names into IP addresses","Digital Navigation Service - routes packets","Direct Node Switch - connects computers"],1,"**DNS** (Domain Name System) is like the internet's phone book. It translates human-readable domain names (e.g. `www.open.ac.uk`) into IP addresses that computers use to locate each other."),
  q(3,"The internet","multiple-choice","What is the difference between the internet and the World Wide Web?",["They are the same thing","The internet is the global network infrastructure; the web is a service (web pages) that runs on it","The web is the network; the internet is a type of browser","The internet is for email; the web is for browsing"],1,"The **internet** is the global network of interconnected computers - the infrastructure. The **World Wide Web** is one service that uses the internet: web pages linked via hyperlinks, accessed using HTTP."),
  q(3,"The internet","multiple-choice","What does UDP (User Datagram Protocol) sacrifice compared to TCP?",["Speed","Reliability - packets may be lost or arrive out of order","Encryption","Compatibility"],1,"**UDP** does not guarantee delivery, order, or error-checking. This makes it **faster** than TCP, which is why it is used for real-time applications like video streaming and online gaming where delays are worse than lost packets."),
  q(3,"The internet","true-false","IPv6 was developed to address the shortage of IPv4 addresses.",["True","False"],0,"True. **IPv4** provides about 4.3 billion addresses (32-bit). **IPv6** uses 128-bit addresses, providing approximately 340 undecillion addresses - more than enough for the foreseeable future."),
  q(3,"The internet","open-answer","Explain the difference between TCP and UDP. Give an example of an application that uses each and explain why it suits that protocol.",[],- 1,"**TCP** (Transmission Control Protocol) guarantees reliable, ordered delivery. If a packet is lost, TCP requests it be resent. This makes it ideal for applications where accuracy is critical, such as **web browsing** or **file downloads**. **UDP** (User Datagram Protocol) is faster but does not guarantee delivery. It is used for real-time applications where small amounts of lost data are acceptable but delays are not - for example **video calls** or **online gaming**, where occasional dropped frames are preferable to the call freezing while waiting for a resend."),

  // Wireless communications
  q(3,"Wireless communications","multiple-choice","What technology do contactless payment cards and Oyster cards typically use?",["Bluetooth","WiFi","RFID / NFC","Infrared"],2,"Contactless cards use **RFID** (Radio-Frequency Identification) or its short-range variant **NFC** (Near Field Communication). The card contains a chip and antenna that communicates with a reader using radio waves."),
  q(3,"Wireless communications","multiple-choice","Bluetooth is primarily designed for:",["Long-range internet access across cities","Short-range wireless communication between devices","Satellite navigation","Broadcasting TV signals"],1,"**Bluetooth** is a short-range wireless technology (typically up to ~10 metres) designed for **personal area networks** - connecting nearby devices like headphones, keyboards, and phones without cables."),
  q(3,"Wireless communications","multiple-choice","Approximately how far does a typical WiFi signal reach indoors?",["5 metres","30-100 metres","1 kilometre","10 kilometres"],1,"A typical WiFi access point has a range of about **30-100 metres** indoors, depending on walls, interference, and the standard used."),
  q(3,"Wireless communications","true-false","WiFi and mobile data (4G/5G) both use radio waves to transmit data wirelessly.",["True","False"],0,"True. Both **WiFi** and **mobile data** use **radio waves**. They operate at different frequencies - WiFi connects to local access points, while mobile data connects to cell towers."),
  q(3,"Wireless communications","multiple-choice","What does RFID stand for?",["Remote Frequency Identification Device","Radio-Frequency Identification","Rapid File Identification","Remote Fibre Interface Device"],1,"**RFID** stands for **Radio-Frequency Identification**. It uses electromagnetic fields to automatically identify and track tags. Used in contactless cards, passports, stock tracking, and animal microchips."),
  q(3,"Wireless communications","multiple-choice","Which wireless technology is typically used to connect a wireless mouse to a laptop?",["NFC","Bluetooth","5G","RFID"],1,"**Bluetooth** is the most common wireless technology for connecting peripherals like wireless mice and keyboards. It operates over short distances (typically up to 10 metres) with relatively low power consumption."),
  q(3,"Wireless communications","true-false","Walls and physical objects can reduce the strength of a WiFi signal.",["True","False"],0,"True. WiFi radio waves can be absorbed and reflected by physical objects - particularly thick walls, metal, and water. Signal strength decreases as you move further from the router or when obstacles are in the way."),
  q(3,"Wireless communications","open-answer","Explain the difference between WiFi and Bluetooth. Give one typical use case for each.",[],- 1,"**WiFi** uses radio waves to connect devices to a local area network (and through it, to the internet). It has a range of roughly 30-100 metres indoors and is designed for high-speed data transfer. Typical use: connecting a laptop to the internet at home. **Bluetooth** is designed for short-range (typically up to 10 metres) low-power connections between personal devices. It does not provide internet access on its own. Typical use: connecting wireless earphones to a phone, or a keyboard to a computer."),

  // The Internet of Things
  q(3,"The Internet of Things","multiple-choice","Which of the following best describes the Internet of Things (IoT)?",["A social network for sharing internet memes","The network of physical objects embedded with sensors and connectivity to exchange data","A new version of the World Wide Web","A type of computer virus"],1,"**IoT** (Internet of Things) refers to everyday physical objects - smart thermostats, wearables, smart fridges, industrial sensors - that are connected to the internet and can collect and exchange data automatically."),
  q(3,"The Internet of Things","true-false","Security and privacy are significant concerns with IoT devices because many collect personal data and may have weak security implementations.",["True","False"],0,"True. IoT devices often collect sensitive data and many have limited security features, default passwords, or infrequent updates - making them targets for attackers."),
  q(3,"The Internet of Things","multiple-choice","Which of the following is NOT an example of an IoT device?",["A smart thermostat that adjusts temperature automatically","A fitness tracker that monitors heart rate","A traditional mechanical alarm clock","A connected street lamp that dims at sunrise"],2,"A **traditional mechanical alarm clock** has no sensors or internet connectivity - it is not an IoT device. The others all have sensors, connectivity, and the ability to exchange data automatically."),
  q(3,"The Internet of Things","multiple-choice","What are the three main components typically found in an IoT device?",["Screen, keyboard, and mouse","Sensors, processor, and connectivity module","RAM, ROM, and CPU","Battery, antenna, and display"],1,"IoT devices typically contain: **sensors** (to collect data), a **processor** (to act on it), and a **connectivity module** (e.g. WiFi or Bluetooth chip) to transmit data."),
  q(3,"The Internet of Things","multiple-choice","What is a major risk of connecting many household devices to the internet via IoT?",["Devices use too much electricity","Each connected device is a potential entry point for cyber attackers","Devices become incompatible with each other","The internet becomes slower globally"],1,"Every IoT device represents a potential **attack surface**. Many IoT devices have weak security (default passwords, no updates), making them vulnerable to being compromised."),
  q(3,"The Internet of Things","multiple-choice","Which of the following is an example of an IoT application in healthcare?",["A social media platform","A wearable heart rate monitor that sends data to a doctor","A database management system","A video game console"],1,"**Wearable health monitors** are a key IoT healthcare application. They continuously track vital signs (heart rate, blood oxygen, etc.) and can automatically alert medical staff to dangerous changes."),
  q(3,"The Internet of Things","open-answer","Describe two benefits and two security or privacy concerns associated with Internet of Things (IoT) devices.",[],- 1,"**Benefits:** IoT devices can automate and optimise tasks - for example, a smart thermostat learns your schedule and reduces energy use when you are away, saving money. Wearable health monitors can track vital signs continuously and alert healthcare providers to problems early. **Security/privacy concerns:** Many IoT devices are produced cheaply with minimal security features and rarely receive software updates, making them vulnerable to hackers. They also collect large amounts of personal data (location, health, daily routines) which could be misused if the data is stolen or sold without consent."),

  // Online communication
  q(3,"Online communication","multiple-choice","What is 'netiquette'?",["A type of internet security protocol","The accepted rules of polite behaviour when communicating online","A tool for measuring network speed","A programming language for web development"],1,"**Netiquette** (internet etiquette) refers to the informal rules of polite and respectful behaviour online - such as not typing in ALL CAPS (perceived as shouting), and not sharing others' private information."),
  q(3,"Online communication","multiple-choice","What is a 'digital footprint'?",["The physical size of a computer's components","The trail of data left behind by online activity","A type of computer virus","A method of wireless encryption"],1,"A **digital footprint** is the trail of data created by online activity - websites visited, social media posts, purchases, and messages sent. It can be used by companies and employers to build a picture of a person."),
  q(3,"Online communication","true-false","Information posted online can always be permanently deleted.",["True","False"],1,"False. Once information is posted online, it can be copied, shared, screenshotted, and cached. Even after deletion, content may remain on servers, in archives, or on others' devices - making truly permanent deletion very difficult."),
  q(3,"Online communication","multiple-choice","What does 'phishing' mean in the context of online security?",["Illegally downloading music files","Fraudulent attempts to obtain sensitive information by disguising as a trustworthy source","Deliberately crashing a website","Sending spam emails for advertising"],1,"**Phishing** is a cyber attack where criminals send fake emails or create fake websites that look legitimate, to trick people into revealing passwords, bank details, or other sensitive information."),
  q(3,"Online communication","multiple-choice","Which of the following is an example of cyberbullying?",["Disagreeing with a friend's opinion in private conversation","Sending repeated threatening messages to someone online to cause distress","Reporting inappropriate content on a platform","Adjusting privacy settings on a social media account"],1,"**Cyberbullying** is the use of digital technology to repeatedly harass, threaten, or humiliate someone. It can have serious mental health consequences."),
  q(3,"Online communication","multiple-choice","What should you check before trusting information found online?",["Whether the website looks colourful and modern","Whether the source is reputable and the information can be verified elsewhere","Whether the page loaded quickly","Whether the URL is short"],1,"Evaluating online information requires checking: whether the **source is reputable** (e.g. academic, government, established news outlet), whether the information can be **verified** by other reliable sources, and when it was **last updated**."),
  q(3,"Online communication","open-answer","Explain what a digital footprint is and describe two ways in which it could affect someone positively or negatively.",[],- 1,"A **digital footprint** is the record of data created by someone's online activities - including social media posts, website visits, purchases, and comments. Positive effects: a professional digital footprint (portfolio work, thoughtful posts, positive reviews) can impress employers and open career opportunities. Negative effects: inappropriate posts or offensive comments online can damage someone's reputation and affect job prospects, even years later. Data collected by companies can also be sold to advertisers or exposed in a data breach, compromising privacy."),

  // The networked society
  q(3,"The networked society","multiple-choice","Which of the following is an example of the 'digital divide'?",["A computer screen cracking","Some people lacking access to the internet or digital technology due to socioeconomic factors","A hacker splitting data across multiple servers","The difference between analogue and digital signals"],1,"The **digital divide** refers to the gap between those who have access to modern ICT and those who do not - often linked to wealth, geography, age, or disability."),
  q(3,"The networked society","true-false","Sharing someone else's personal data online without their permission is generally considered both unethical and may be illegal under data protection laws.",["True","False"],0,"True. Sharing personal data without consent is unethical and likely illegal. In the UK, the **UK GDPR** governs how personal data must be handled. Violations can result in significant fines."),
  q(3,"The networked society","multiple-choice","What does GDPR stand for?",["General Digital Privacy Regulation","Global Data Protection Rules","General Data Protection Regulation","Government Digital Processing Requirement"],2,"**GDPR** stands for **General Data Protection Regulation**. Adopted as UK GDPR in the UK post-Brexit, it governs how personal data must be collected, stored, processed, and shared."),
  q(3,"The networked society","multiple-choice","What is 'malware'?",["A type of network cable","Software designed to disrupt, damage, or gain unauthorised access to a computer system","A database management tool","A web browser extension"],1,"**Malware** (malicious software) is any software designed to cause harm. Types include **viruses** (self-replicating), **ransomware** (encrypts files and demands payment), **trojans** (disguised as legitimate software), and **spyware** (collects information secretly)."),
  q(3,"The networked society","multiple-choice","Which of the following best describes an ethical issue raised by artificial intelligence systems?",["AI systems are too slow to be useful","AI decision-making can be biased if trained on unrepresentative data","AI systems always respect user privacy","AI systems cannot make mistakes"],1,"AI systems learn from training data. If that data reflects existing biases (e.g. historical discrimination), the AI may perpetuate or amplify those biases - leading to unfair outcomes in areas like hiring or lending."),
  q(3,"The networked society","multiple-choice","What does 'open source' software mean?",["Software that is freely available and whose source code can be viewed, modified, and shared","Software that requires an internet connection","Software that is only available on open-source operating systems","Software with no licence restrictions"],0,"**Open source** software has its source code made publicly available. Anyone can view, use, modify, and distribute it (subject to the specific licence terms). Examples include Linux, Firefox, and Android."),
  q(3,"The networked society","open-answer","Explain what the 'digital divide' means and suggest two ways it could be reduced.",[],- 1,"The **digital divide** is the gap between people who have access to digital technology and the internet, and those who do not. Factors include income (cost of devices and broadband), geography (rural areas with poor infrastructure), age (older people less familiar with technology), and disability. Ways to reduce it include: government-subsidised broadband and device schemes for low-income households; digital literacy programmes in schools, libraries, and community centres; public WiFi in towns and cities; and investment in broadband infrastructure in rural areas."),

  // ─────────────────────────────────────────────
  // BLOCK 4 - Maths Supplement
  // ─────────────────────────────────────────────

  // Percentages
  q(4,"Percentages","multiple-choice","What is 25% of 200?",["25","50","75","100"],1,"25% of 200 = (25/100) x 200 = 0.25 x 200 = **50**."),
  q(4,"Percentages","multiple-choice","A hard drive has 500 GB capacity. 120 GB is used. What percentage is used?",["12%","20%","24%","41.7%"],2,"(120 / 500) x 100 = **24%** of the drive is used."),
  q(4,"Percentages","multiple-choice","A file is compressed from 800 KB to 600 KB. What is the percentage reduction in size?",["20%","25%","33%","75%"],1,"Reduction = 800 - 600 = 200 KB. Percentage = (200 / 800) x 100 = **25%** reduction."),
  q(4,"Percentages","true-false","To increase a value by 15%, you multiply it by 1.15.",["True","False"],0,"True. To increase by 15%, multiply by (1 + 0.15) = **1.15**. For example, 200 x 1.15 = 230. To decrease by 15%, multiply by 0.85."),
  q(4,"Percentages","multiple-choice","A quiz score was 18 out of 24. What is this as a percentage?",["60%","70%","75%","80%"],2,"(18 / 24) x 100 = 0.75 x 100 = **75%**."),
  q(4,"Percentages","multiple-choice","If CPU usage drops from 80% to 60%, by how much has it decreased?",["10 percentage points","20 percentage points","25% relative decrease","33% relative decrease"],1,"80% - 60% = **20 percentage points** decrease. Note: this is different from a 25% relative decrease, which would be (20/80) x 100 = 25%."),
  q(4,"Percentages","multiple-choice","A broadband package advertises speeds of 100 Mbps but only delivers 75 Mbps. What percentage of the advertised speed is being delivered?",["25%","50%","75%","80%"],2,"(75 / 100) x 100 = **75%** of the advertised speed is being delivered."),
  q(4,"Percentages","open-answer","A hard drive is 60% full with 240 GB of data. What is the total capacity of the hard drive? Show your working.",[],- 1,"If 240 GB represents 60% of the total capacity, then 1% = 240/60 = 4 GB. Total capacity = 4 x 100 = **400 GB**. Or using algebra: 0.6 x capacity = 240, so capacity = 240 / 0.6 = 400 GB."),

  // Exponent notation
  q(4,"Exponent notation","multiple-choice","What is the value of 2^10?",["20","512","1024","2048"],2,"2^10 = 2 x 2 x 2 x 2 x 2 x 2 x 2 x 2 x 2 x 2 = **1024**. This is why 1 KB = 1024 bytes."),
  q(4,"Exponent notation","multiple-choice","What is the value of 2^8?",["64","128","256","512"],2,"2^8 = **256**. One byte has 8 bits and can represent 2^8 = 256 different values (0 to 255)."),
  q(4,"Exponent notation","multiple-choice","Which rule applies when multiplying two numbers with the same base?",["Multiply the exponents","Add the exponents","Subtract the exponents","Divide the exponents"],1,"When multiplying with the same base, **add** the exponents: `2^3 x 2^4 = 2^7 = 128`. Check: 8 x 16 = 128. Correct!"),
  q(4,"Exponent notation","true-false","2^0 = 0",["True","False"],1,"False. Any non-zero number raised to the power 0 equals **1**. So 2^0 = **1**. This follows from the rule that dividing equal bases means subtracting exponents: 2^3 / 2^3 = 2^0 = 1."),
  q(4,"Exponent notation","multiple-choice","A hard drive has capacity of 2^40 bytes. What is this called?",["1 gigabyte","1 terabyte","1 petabyte","1 exabyte"],1,"2^40 bytes = **1 terabyte** (TB). Memory units: 2^10=KB, 2^20=MB, 2^30=GB, 2^40=**TB**."),
  q(4,"Exponent notation","multiple-choice","What is 2^4 x 2^3?",["2^12","2^7","2^1","24"],1,"2^4 x 2^3 = 2^(4+3) = **2^7** = 128. When multiplying the same base, add the exponents."),

  // Scientific notation
  q(4,"Scientific notation","multiple-choice","Express 4,500,000 in scientific notation.",["4.5 x 10^5","4.5 x 10^6","45 x 10^5","0.45 x 10^7"],1,"4,500,000 = **4.5 x 10^6**. The coefficient must be between 1 and 10. The decimal moves 6 places left."),
  q(4,"Scientific notation","multiple-choice","A processor runs at 3 GHz. Express this in Hz using scientific notation.",["3 x 10^6 Hz","3 x 10^9 Hz","3 x 10^12 Hz","3 x 10^3 Hz"],1,"1 GHz = 10^9 Hz. So 3 GHz = **3 x 10^9 Hz**. 'Giga' means 10^9 (1 billion)."),
  q(4,"Scientific notation","multiple-choice","Which of the following represents 0.00035 in correct scientific notation?",["3.5 x 10^4","3.5 x 10^-4","35 x 10^-5","0.35 x 10^-3"],1,"0.00035 = **3.5 x 10^-4**. The coefficient must be 1 to 10, so 3.5. The exponent is negative because we moved the decimal 4 places to the right."),
  q(4,"Scientific notation","true-false","In scientific notation, the number part must always be between 1 and 10.",["True","False"],0,"True. In standard scientific notation, the coefficient must be at least 1 but less than 10. `45 x 10^3` is not standard - it should be written as `4.5 x 10^4`."),
  q(4,"Scientific notation","multiple-choice","Convert 2.5 x 10^-3 to a decimal number.",["250","0.25","0.025","0.0025"],3,"2.5 x 10^-3 = 2.5 / 1000 = **0.0025**. A negative exponent means the decimal point moves to the left (making the number smaller)."),

  // Binary and number systems
  q(4,"Binary and number systems","multiple-choice","Convert binary 1101 to decimal.",["11","12","13","14"],2,"`1101` = (1x8) + (1x4) + (0x2) + (1x1) = 8 + 4 + 0 + 1 = **13**."),
  q(4,"Binary and number systems","multiple-choice","Convert decimal 10 to binary.",["1000","1001","1010","1011"],2,"10 in binary: 10 = 8+2 = **1010**. (10/2=5 r0; 5/2=2 r1; 2/2=1 r0; 1/2=0 r1. Read remainders upward: 1010.)"),
  q(4,"Binary and number systems","multiple-choice","Convert binary 11110000 to decimal.",["120","240","192","128"],1,"`11110000` = 128+64+32+16+0+0+0+0 = **240**."),
  q(4,"Binary and number systems","multiple-choice","Convert decimal 255 to binary.",["11111110","11111111","10000000","01111111"],1,"255 = 128+64+32+16+8+4+2+1 = **11111111** (all eight bits set to 1). This is the maximum value of one byte."),
  q(4,"Binary and number systems","multiple-choice","Convert decimal 64 to binary.",["01000000","00100000","01100000","10000000"],0,"64 = 2^6 = **01000000** in 8-bit binary. Only the bit with place value 64 is set to 1."),
  q(4,"Binary and number systems","multiple-choice","What is the hexadecimal value of decimal 255?",["EE","FE","FF","F0"],2,"255 in hex: 255 / 16 = 15 remainder 15. Both digits are 15 = F. So 255 = **FF** in hexadecimal."),
  q(4,"Binary and number systems","multiple-choice","What is the decimal value of hexadecimal A5?",["105","155","165","175"],2,"A5 hex: A = 10, 5 = 5. Value = (10 x 16) + (5 x 1) = 160 + 5 = **165**."),
  q(4,"Binary and number systems","multiple-choice","How many different values can be represented by 4 bits (a nibble)?",["4","8","16","32"],2,"4 bits can represent 2^4 = **16** different values (0000 through 1111, or 0 through 15). Each hex digit represents exactly 4 bits."),
  q(4,"Binary and number systems","multiple-choice","Convert binary 10000000 to decimal.",["64","128","192","256"],1,"`10000000` = 2^7 = **128**. In an 8-bit byte, place values from right to left are: 1, 2, 4, 8, 16, 32, 64, **128**."),
  q(4,"Binary and number systems","multiple-choice","What is 1 megabyte (MB) in bytes?",["1000 bytes","1024 bytes","1,048,576 bytes","1,000,000,000 bytes"],2,"1 MB = 1024 KB = 1024 x 1024 bytes = **1,048,576 bytes** (2^20). This is the binary definition used in computing."),
  q(4,"Binary and number systems","true-false","Each hexadecimal digit can be represented by exactly 4 binary bits.",["True","False"],0,"True. Hexadecimal is base-16. Since 2^4 = 16, each hex digit maps to exactly 4 binary bits. For example, `FF` hex = `11111111` binary."),
  q(4,"Binary and number systems","multiple-choice","Convert decimal 45 to binary.",["100101","101101","110001","111001"],1,"45 = 32+8+4+1 = **101101**. (45/2=22 r1; 22/2=11 r0; 11/2=5 r1; 5/2=2 r1; 2/2=1 r0; 1/2=0 r1. Read upward: 101101.)"),
  q(4,"Binary and number systems","open-answer","Convert the decimal number 45 to binary. Show your working.",[],- 1,"To convert 45 to binary, repeatedly divide by 2 and record remainders: 45/2=22 r**1**; 22/2=11 r**0**; 11/2=5 r**1**; 5/2=2 r**1**; 2/2=1 r**0**; 1/2=0 r**1**. Reading remainders from bottom to top: **101101**. Check: 32+8+4+1 = 45. Correct!"),

  // Equations and substitution
  q(4,"Equations and substitution","multiple-choice","If speed = distance / time, and distance = 150 km and time = 3 hours, what is the speed?",["50 km/h","450 km/h","0.02 km/h","147 km/h"],0,"speed = distance / time = 150 / 3 = **50 km/h**."),
  q(4,"Equations and substitution","multiple-choice","Rearrange the formula speed = distance / time to make distance the subject.",["distance = speed + time","distance = speed / time","distance = speed x time","distance = time / speed"],2,"Starting with speed = distance / time, multiply both sides by time: **distance = speed x time**."),
  q(4,"Equations and substitution","multiple-choice","If file_size = bit_depth x sample_rate x duration, what is the file size of a 3-second audio clip with bit depth 16 and sample rate 44,100 Hz?",["2,116,800 bits","2,000,000 bits","132,300 bits","44,100 bits"],0,"file_size = 16 x 44,100 x 3 = 16 x 132,300 = **2,116,800 bits**."),
  q(4,"Equations and substitution","true-false","Substitution means replacing a variable in a formula with its numerical value.",["True","False"],0,"True. **Substitution** is the process of replacing a variable (letter) in a formula with its known numerical value, then calculating the result. It is a core skill for solving computing-related calculations."),
  q(4,"Equations and substitution","multiple-choice","If transmission_time = file_size / bandwidth, and file_size = 500 MB and bandwidth = 100 Mbps, how long does the transfer take?",["5 seconds","50 seconds","0.5 seconds","5000 seconds"],0,"transmission_time = 500 / 100 = **5 seconds**. (Assuming file_size and bandwidth use the same units.)"),

  // Inverse square law
  q(4,"Inverse square law","multiple-choice","According to the inverse square law, if you double your distance from a WiFi router, what happens to the signal strength?",["It halves","It drops to one quarter of its original value","It stays the same","It doubles"],1,"The inverse square law states intensity proportional to 1/d^2. If distance doubles (d x 2), intensity changes by 1/(2)^2 = 1/4. Signal drops to **one quarter** of its original strength."),
  q(4,"Inverse square law","multiple-choice","The inverse square law formula is I proportional to 1/d^2. If distance increases by a factor of 3, intensity changes by a factor of:",["1/3","1/6","1/9","1/27"],2,"If d increases by 3, then d^2 increases by 3^2 = 9. So intensity decreases by a factor of **1/9** (to one ninth of its original value)."),
  q(4,"Inverse square law","true-false","The inverse square law applies to light, sound, and radio signals - anything that spreads outward equally in all directions.",["True","False"],0,"True. The inverse square law applies to any signal that radiates outward equally from a point source - including **light**, **sound**, **gravity**, and **radio waves** like WiFi. Intensity decreases with the square of the distance."),
  q(4,"Inverse square law","multiple-choice","A WiFi signal has strength 100 units at 1 metre from the router. What is its strength at 5 metres?",["20 units","10 units","5 units","4 units"],3,"At 5 metres: I = 100 x (1/5)^2 = 100 x 1/25 = **4 units**. The signal drops to 4% of its strength at 1 metre when you move 5 times further away."),
  q(4,"Inverse square law","multiple-choice","If the inverse square law applies, at what distance would a signal be 1/16 of its original strength?",["4 times the original distance","8 times the original distance","16 times the original distance","2 times the original distance"],0,"If I proportional to 1/d^2 and we want 1/16 of original: 1/d^2 = 1/16, so d^2 = 16, therefore d = 4. The signal drops to 1/16 at **4 times** the original distance."),
  q(4,"Inverse square law","open-answer","Explain the inverse square law in the context of wireless networking. Give an example with numbers to illustrate your answer.",[],- 1,"The **inverse square law** states that signal intensity decreases with the square of the distance from the source. In wireless networking, this means WiFi signal strength falls rapidly as you move away from a router. For example, if a signal has strength 100 units at 1 metre, at 2 metres (twice the distance) the strength is 100 / 2^2 = 100 / 4 = 25 units - a quarter of the original. At 3 metres, strength = 100 / 9 = approximately 11 units. This is why moving to another room or floor can dramatically weaken a WiFi connection."),
]
